    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.form-subtitle {
    -fx-font-size: 12px;
    -fx-text-fill: #9ca3af;
}

.field-label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
