/* Form Panel Styles */
.form-panel {
    -fx-background-color: white;
    -fx-background-radius: 16;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 16;
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.08), 15, 0, 0, 4);
}

.form-header {
    -fx-border-color: #f0f0f0;
    -fx-border-width: 0 0 1 0;
    -fx-padding: 0 0 16 0;
    -fx-margin: 0 0 16 0;
}

.form-title {
    -fx-font-size: 20px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.form-subtitle {
    -fx-font-size: 12px;
    -fx-text-fill: #9ca3af;
}

.field-label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #374151;
}

.input-field {
    -fx-background-color: #f9fafb;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
    -fx-font-size: 13px;
}

.input-field:focused {
    -fx-border-color: #3b82f6;
    -fx-background-color: white;
}

.input-field:hover {
    -fx-border-color: #d1d5db;
}

.image-preview-container {
    -fx-background-color: #f3f4f6;
    -fx-background-radius: 8;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 8;
    -fx-pref-width: 90;
    -fx-pref-height: 60;
    -fx-border-width: 1;
}

.image-placeholder {
    -fx-fill: #e5e7eb;
    -fx-arc-width: 8;
    -fx-arc-height: 8;
}

.pdf-label {
    -fx-font-size: 12px;
    -fx-text-fill: #6b7280;
}

/* Buttons */
.primary-button {
    -fx-background-color: #3b82f6;
    -fx-text-fill: white;
    -fx-background-radius: 10;
    -fx-padding: 12 24;
    -fx-font-size: 14px;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.primary-button:hover {
    -fx-background-color: #2563eb;
}

.primary-button:pressed {
    -fx-background-color: #1d4ed8;
}

.secondary-button {
    -fx-background-color: #f3f4f6;
    -fx-text-fill: #374151;
    -fx-background-radius: 8;
    -fx-padding: 8 16;
    -fx-font-size: 13px;
    -fx-font-weight: 500;
    -fx-cursor: hand;
}

.secondary-button:hover {
    -fx-background-color: #e5e7eb;
}

.danger-button {
    -fx-background-color: #fee2e2;
    -fx-text-fill: #dc2626;
    -fx-background-radius: 10;
    -fx-padding: 12 24;
    -fx-font-size: 14px;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.danger-button:hover {
    -fx-background-color: #fecaca;
}

.danger-button:pressed {
    -fx-background-color: #fca5a5;
}

.danger-button:disabled {
    -fx-background-color: #f3f4f6;
    -fx-text-fill: #9ca3af;
}

.icon-btn {
    -fx-background-color: transparent;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 8;
    -fx-padding: 8 12;
    -fx-cursor: hand;
}

.icon-btn:hover {
    -fx-background-color: #f3f4f6;
}

.close-btn {
    -fx-background-color: transparent;
    -fx-text-fill: #9ca3af;
    -fx-font-size: 18px;
    -fx-cursor: hand;
    -fx-padding: 4 8;
}

.close-btn:hover {
    -fx-background-color: #fee2e2;
    -fx-text-fill: #dc2626;
}

/* Search field */
.search-field {
    -fx-background-color: #f3f4f6;
    -fx-border-color: transparent;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
}

.search-field:focused {
    -fx-border-color: #3b82f6;
    -fx-background-color: white;
}

/* Cards scroll */
.cards-scroll {
    -fx-background-color: transparent;
}

.cards-scroll > .viewport {
    -fx-background-color: transparent;
}

/* Form scroll */
.form-scroll {
    -fx-background-color: transparent;
    -fx-border-width: 0;
}

.form-scroll > .viewport {
    -fx-background-color: transparent;
}

