}

.music-actions-menu {
    -fx-background-color: white;
    -fx-background-radius: 10;
    -fx-border-color: #d9e2ef;
    -fx-border-radius: 10;
    -fx-padding: 4;
    -fx-effect: dropshadow(gaussian, rgba(31, 45, 70, 0.14), 12, 0.14, 0, 3);
}

.music-actions-menu .menu-item {
    -fx-background-color: transparent;
    -fx-background-radius: 8;
    -fx-padding: 7 12 7 12;
}

.music-actions-menu .menu-item .label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #223247;
}

.music-actions-menu .menu-item:focused,
.music-actions-menu .menu-item:hover {
    -fx-background-color: #edf2ff;
}

.music-actions-menu .menu-item.music-actions-delete .label {
    -fx-text-fill: #c62828;
}

.music-actions-menu .menu-item.music-actions-delete:focused,
.music-actions-menu .menu-item.music-actions-delete:hover {
    -fx-background-color: #fff1f2;
}
